"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[3973],{2565(e){e.exports=JSON.parse('{"tag":{"label":"machine-learning","permalink":"/gsf-patterns/tags/machine-learning","allTagsPath":"/gsf-patterns/tags","count":12,"items":[{"id":"architecture/system-topology/serverless-model-development","title":"Adopt serverless architecture for AI/ML workload processes","description":"Building an ML model takes significant computing resources that need to be optimized for efficient utilization.","permalink":"/gsf-patterns/architecture/system-topology/serverless-model-development"},{"id":"development/pre-trained-transfer-learning","title":"Leverage pre-trained models and transfer learning","description":"Fine-tune existing pre-trained models instead of training from scratch to dramatically reduce the compute, energy, and time required for model development.","permalink":"/gsf-patterns/development/pre-trained-transfer-learning"},{"id":"development/optimize-agent-orchestration-reduce-model-calls","title":"Optimize agent orchestration to reduce unnecessary model calls","description":"Design agentic AI workflows to minimise redundant model invocations and unnecessary compute through caching, conditional logic, and efficient orchestration patterns.","permalink":"/gsf-patterns/development/optimize-agent-orchestration-reduce-model-calls"},{"id":"development/data-handling/optimize-data-storage-ai-training","title":"Optimize data storage formats for AI training and inference","description":"Use efficient storage formats, compression, and indexing strategies for AI datasets and embeddings to reduce storage footprint, data transfer, and retrieval compute.","permalink":"/gsf-patterns/development/data-handling/optimize-data-storage-ai-training"},{"id":"architecture/system-topology/run-ai-models-edge","title":"Run AI models at the edge","description":"Deploy AI inference on edge devices or local infrastructure to reduce data transfer, network energy use, and reliance on centralised cloud compute.","permalink":"/gsf-patterns/architecture/system-topology/run-ai-models-edge"},{"id":"architecture/technology-selection/energy-efficent-framework","title":"Select a more energy efficient AI/ML framework","description":"Training an AI model implies a significant carbon footprint. The underlying framework used for the development, training, and deployment of AI/ML needs to be evaluated and considered to ensure the process is as energy efficient as possible.","permalink":"/gsf-patterns/architecture/technology-selection/energy-efficent-framework"},{"id":"architecture/system-topology/efficient-hardware-ai-workloads","title":"Select efficient accelerators and instance types for AI workloads","description":"Match AI workloads to the most energy-efficient hardware accelerator or instance type to improve utilisation and reduce energy consumption per inference or training run.","permalink":"/gsf-patterns/architecture/system-topology/efficient-hardware-ai-workloads"},{"id":"development/select-efficient-ml-frameworks-inference-runtimes","title":"Select efficient ML frameworks and inference runtimes","description":"Choose ML frameworks and inference runtimes that best match your hardware and workload to reduce compute overhead and improve energy efficiency across training and production inference.","permalink":"/gsf-patterns/development/select-efficient-ml-frameworks-inference-runtimes"},{"id":"operations/carbon-aware-ai-scheduling","title":"Use carbon-aware scheduling and region selection for AI workloads","description":"Reduce the carbon impact of AI workloads by running them in cloud regions with lower grid carbon intensity and scheduling deferrable jobs during periods of high renewable energy availability.","permalink":"/gsf-patterns/operations/carbon-aware-ai-scheduling"},{"id":"architecture/technology-selection/energy-efficent-models","title":"Use energy efficient AI/ML models","description":"Evaluate and use alternative, more energy efficient, models that provide similar functionality.","permalink":"/gsf-patterns/architecture/technology-selection/energy-efficent-models"},{"id":"architecture/system-topology/on-demand-execution-ai-agent-workloads","title":"Use on-demand execution for AI and agent workloads","description":"Trigger AI and agent workloads only when needed using serverless or event-driven platforms to eliminate idle compute and reduce unnecessary energy consumption.","permalink":"/gsf-patterns/architecture/system-topology/on-demand-execution-ai-agent-workloads"},{"id":"development/right-sized-energy-efficient-ai-models","title":"Use right-sized and energy-efficient AI models","description":"Select and optimize AI models that are appropriately sized for the task to reduce compute, memory, and energy consumption during training and inference.","permalink":"/gsf-patterns/development/right-sized-energy-efficient-ai-models"}],"unlisted":false}}')}}]);